#include<bits/stdc++.h>
using namespace std;
int n,t,tim=1;
struct player
{
    bool killed,died,usedskill;
    bool used_du,used_jie,lieren_cankill;
    int dietime;
    int sf;
    void operator=(const player&b)
    {
        killed=b.killed;
        died=b.died;
        usedskill=b.usedskill;
        used_du=b.used_du;
        used_jie=b.used_jie;
        dietime=b.dietime;
        sf=b.sf;
    }
}now[101];
player ver[101][101];
bool wrong;
bool live(int x)
{
    return (!now[x].killed)&&(!now[x].died);
}
void returnto(int x)
{
    for(int i=1;i<=n;i++)
    {
        now[i]=ver[x][i];
    }
}
void kill(int target)
{
    if(wrong)
    {
        return;
    }
    if(!live(target))
    {
        wrong=true;
        return;
    }
    if(now[target].sf==3&&now[target].usedskill)
    {
        now[target].usedskill=false;
    }
    now[target].killed=true;
}
void wolf_kill(int id,int target)
{
    if(wrong)
    {
        return;
    }
    if(now[id].sf!=1||now[id].usedskill)
    {
        wrong=true;
        return;
    }
    if(!live(id)||!live(target)||id==target)
    {
        wrong=true;
        return;
    }
    now[id].usedskill=true;
    kill(target);
}
void witch_du(int id,int target)
{
    if(wrong)
    {
        return;
    }
    if(now[id].sf!=4||now[id].usedskill||now[id].used_du)
    {
        wrong=true;
        return;
    }
    if(!live(id)||!live(target))
    {
        wrong=true;
        return;
    }
    now[id].usedskill=true;
    now[id].used_du=true;
    kill(target);
}
void witch_jie(int id,int target)
{
    if(wrong)
    {
        return;
    }
    if(now[id].sf!=4||now[id].usedskill||now[id].used_jie)
    {
        wrong=true;
        return;
    }
    if(now[id].killed&&id!=target)
    {
        wrong=true;
        return;
    }
    if(now[id].died||!now[target].killed)
    {
        wrong=true;
        return;
    }
    now[id].usedskill=true;
    now[id].used_jie=true;
    now[target].killed=false;
}
void lieren_kill(int id,int target)
{
    if(wrong)
    {
        return;
    }
    if(now[id].sf!=3||now[id].usedskill)
    {
        wrong=true;
        return;
    }
    if(!now[id].killed||!live(target))
    {
        wrong=true;
        return;
    }
    now[id].usedskill=true;
    kill(target);
}
void day()
{
    for(int i=1;i<=n;i++)
    {
        if(now[i].killed)
        {
            if(now[i].sf==3&&(!now[i].usedskill))
            {
                wrong=true;
                break;
            }
        }
    }
    if(wrong)
    {
        printf("Wrong\n");
        returnto(tim-1);
        for(int i=1;i<=n;i++)
        {
            ver[tim][i]=now[i];
            // printf("now[%d].killed=%d,died=%d\n",i,(int)(now[i].killed),(int)(now[i].died));
        }
        tim++;
        wrong=false;
        return;
    }
    vector<int> v;
    for(int i=1;i<=n;i++)
    {
        if(now[i].killed)
        {
            v.push_back(i);
            now[i].killed=false;
            now[i].died=true;
            now[i].dietime=tim;
        }
        now[i].usedskill=false;
        ver[tim][i]=now[i];
    }
    if(v.empty())
    {
        printf("Safe\n");
        tim++;
        return;
    }
    printf("%d ",(int)(v.size()));
    for(int i:v)
    {
        printf("%d ",i);
    }
    printf("\n");
    tim++;
}
void skill(int op,int id1,int id2)
{
    if(wrong||op<0||op>3||id1<1||id1>n||id2<1||id2>n)
    {
        wrong=true;
        return;
    }
    if(op==0)
    {
        wolf_kill(id1,id2);
    }
    else if(op==1)
    {
        witch_du(id1,id2);
    }
    else if(op==2)
    {
        witch_jie(id1,id2);
    }
    else
    {
        lieren_kill(id1,id2);
    }
}
int main()
{
    scanf("%d%d",&t,&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&ver[0][i].sf);
    }
    returnto(0);
    for(int i=1;i<=t;i++)
    {
        int m;
        scanf("%d",&m);
        while(m--)
        {
            int x,y,z;
            scanf("%d%d%d",&x,&y,&z);
            skill(x,y,z);
        }
        day();
    }
    return 0;
}
